  ('optician-moex-01896', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關硬式隱形眼鏡偏位之情形何者最正確？①順散光較易偏上位  ②逆散光較易偏下位  ③加大鏡', '["鏡片邊挑（edge clearance）太大易偏位", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
