  ('optician-moex-01898', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '若患者戴上軟式隱形眼鏡後抱怨眨眼之後視力會先模糊再變清楚，此時的鏡片會有何表現，而又該 如何調整隱形眼鏡？', '["此時鏡片之滑動量小於1 mm", "此時眼睛向上注視時，鏡片不會有明顯移動", "將鏡片直徑縮小", "改用較陡的基弧半徑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
